#include <bits/stdc++.h>
using namespace std;
const int mod=1e4+7,N=2e5+5;
int n,w[N],mx,f[N];
long long ans;
bool b[N];
vector<int> g[N];
void dfs(int x){
	b[x]=1;
	int len=g[x].size();
	long long sum=0;
	priority_queue<int> q;
	for(int i=0;i<len;i++)
		if(!b[g[x][i]]){
			q.push(w[g[x][i]]);
			f[g[x][i]]=x,dfs(g[x][i]),ans+=1LL*sum*w[g[x][i]]%mod,ans%=mod,sum+=w[g[x][i]],sum%=mod;
		}
	if(q.size()){
		int tmp=q.top();
		q.pop();
		if(q.size())
			mx=max(mx,tmp*q.top());
	}
	if(f[f[x]])
		ans+=1LL*w[x]*w[f[f[x]]]%mod,ans%=mod,mx=max(mx,w[x]*w[f[f[x]]]);
}
int main(){
	scanf("%d",&n);
	for(int i=1;i<n;i++){
		int u,v;
		scanf("%d%d",&u,&v);
		g[u].push_back(v),g[v].push_back(u);
	}
	for(int i=1;i<=n;i++)
		scanf("%d",&w[i]);
	dfs(1);
	printf("%d %lld",mx,ans*2%mod);
	return 0;
}
